    /**
     * Optional arguments for {@link Env#checks}
     *
     */
    public static class ChecksArguments {
        private List<String> include;

        private Boolean noGenerate;

        /**
         * Only include checks matching the specified patterns
         */
        public ChecksArguments withInclude(List<String> include) {
            this.include = include;
            return this;
        }

        /**
         * When true, only return annotated check functions; exclude generate-as-checks
         */
        public ChecksArguments withNoGenerate(Boolean noGenerate) {
            this.noGenerate = noGenerate;
            return this;
        }

        Arguments toArguments() {
            Arguments.Builder builder = Arguments.newBuilder();
            if (include != null) {
                builder.add("include", this.include);
            }

            if (noGenerate != null) {
                builder.add("noGenerate", this.noGenerate);
            }

                    return builder.build();
        }
    }

